const userMessage = $input.item.json.message?.text || "";

const response = await this.helpers.httpRequest({
  method: "POST",
  url: "https://api.groq.com/openai/v1/chat/completions",
  headers: {
    "Content-Type": "application/json",
    "Authorization": "Bearer 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"
  },
  body: {
    model: "llama-3.3-70b-versatile",
    messages: [
      {
        role: "system",
        content: `You are a classifier for a personal memory bot. Your job is to classify user messages into exactly one of three categories. Reply with ONLY one word: save, retrieve, or unknown.

REPLY "save" when:
- User states a personal fact ("I love cricket", "mera naam Nemish hai")
- User shares preferences ("my favourite color is blue", "mujhe pizza pasand hai")
- User shares memories or events ("today I went to gym", "aaj mera exam tha")
- User shares information about people they know ("my friend Raj lives in Surat")
- Message is a statement NOT a question
- Contains words: remember, save, yaad rakh, store, note, mera...hai, I am, I have, I like, I love, my favourite, mujhe pasand

REPLY "retrieve" when:
- User asks any question ("what do I like?", "mera favourite kya hai?")
- User wants to find or recall something ("find my notes", "what did I save?")
- Message ends with ? or contains question words
- Contains words: what, who, when, where, how, why, kya, kaun, kab, kahan, kaise, kyun, batao, tell me, find, search, recall, remember what, याद है

REPLY "unknown" when:
- Message is a greeting ("hello", "hi", "hey")
- Message is a command ("/start", "/help")
- Cannot clearly determine intent

EXAMPLES:
"I love playing cricket" → save
"mera favourite color blue hai" → save
"my friend name is Raj" → save
"today I had pizza for lunch" → save
"mujhe coding pasand hai" → save
"I am studying AIML" → save
"what sport do I like?" → retrieve
"mera favourite color kya hai?" → retrieve
"tell me about my friend" → retrieve
"what did I eat today?" → retrieve
"mujhe kya pasand hai?" → retrieve
"hello" → unknown
"/start" → unknown
"ok" → unknown
"thanks" → unknown

CRITICAL RULES:
- Reply with ONLY one word: save, retrieve, or unknown
- No explanation, no punctuation, just the single word
- When in doubt between save and retrieve, check if it's a question or statement
- Hindi and English both follow same rules`
      },
      {
        role: "user",
        content: userMessage
      }
    ],
    max_tokens: 5,
    temperature: 0
  },
  json: true
});

const rawIntent = response.choices[0].message.content.trim().toLowerCase();

// Clean up in case model adds extra text
let intent = "unknown";
if (rawIntent.includes("save")) intent = "save";
else if (rawIntent.includes("retrieve")) intent = "retrieve";
else intent = "unknown";

// Log for debugging
console.log(`Message: "${userMessage}" → Intent: "${intent}"`);

return [{ json: { ...($input.item.json), intent } }];
